-- ═══════════════════════════════════════════════════════════════════════════
-- REGULIS — California Tenant Protection Act (AB 1482)
-- ═══════════════════════════════════════════════════════════════════════════

-- AB 1482 — Rent Cap
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_089', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1946.2, 1947.12-1947.13 (AB 1482)', 'CC §§ 1946.2/1947.12', 'California Tenant Protection Act — Rent Cap and Just Cause Eviction', 'AB 1482 (effective 1/1/2020, extended through 1/1/2030) caps annual rent increases at 5% + local CPI (max 10%) and requires just cause for eviction of tenants in possession 12+ months. Applies to most residential properties with specified exemptions for single-family homes (with notice), new construction (15 years), and owner-occupied duplexes.', '["Rent increase cap: lesser of 5% + local CPI or 10% per year","Just cause required for eviction after 12 months tenancy","At-fault just cause includes nonpayment, breach, nuisance, criminal activity, refusal to allow access, subletting violation, refusal to sign renewal, employee tenancy ended","No-fault just cause includes owner move-in, withdrawal from rental market (Ellis Act), government order, substantial remodel","Relocation assistance or rent waiver required for no-fault evictions","Written notice of AB 1482 rights required to tenants","Exemptions: single-family (with notice), new construction (15 yrs), owner-occupied duplex, certain ADUs"]', '[{"section":"1947.12(a)","description":"Rent increase cap — 5% + CPI or 10%"},{"section":"1947.12(c)","description":"Exemptions from rent cap"},{"section":"1946.2(a)","description":"Just cause eviction requirement"},{"section":"1946.2(b)","description":"At-fault just cause grounds"},{"section":"1946.2(c)","description":"No-fault just cause grounds"},{"section":"1946.2(d)","description":"Relocation assistance requirements"},{"section":"1947.12(d)","description":"Notice to tenants of rights"},{"section":"1947.13","description":"Disclosure requirements in lease"}]', '["rent_increase_notice","eviction_notice","lease_agreement","AB_1482_notice","relocation_assistance_offer","3_day_notice","30_day_notice","60_day_notice"]', '["california-housing-tenant-audit"]', 'California Superior Court / Local Rent Boards', 1, 1, datetime('now'), datetime('now'));

-- Costa-Hawkins Rental Housing Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_090', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1954.50-1954.535 (Costa-Hawkins)', 'CC §§ 1954.50-535', 'Costa-Hawkins Rental Housing Act — Vacancy Decontrol and Preemption', 'Limits local rent control ordinances by guaranteeing landlords the right to set initial rental rate for new tenancies (vacancy decontrol) and exempting certain housing types from local rent control. Single-family homes and condominiums are exempt from local rent ordinances. Does NOT preempt AB 1482 state rent caps.', '["Landlord may establish initial rental rate for new tenancy","Single-family homes exempt from local rent control","Condominiums/townhouses exempt from local rent control","New construction after local rent ordinance adoption is exempt","Vacancy decontrol: landlord may raise rent to market upon vacancy","Does not preempt just cause eviction ordinances","Does not preempt AB 1482 statewide rent cap","Local ordinances may not control rents on exempt units"]', '[{"section":"1954.50","description":"Legislative findings and intent"},{"section":"1954.51","description":"Definitions — owner, comparable units"},{"section":"1954.52","description":"Vacancy decontrol — right to set initial rent"},{"section":"1954.53","description":"Exemptions — single-family, condos, new construction"},{"section":"1954.535","description":"Severability"}]', '["rent_increase_notice","local_rent_ordinance_filing","vacancy_notice","lease_agreement"]', '["california-housing-tenant-audit"]', 'California Superior Court', 1, 1, datetime('now'), datetime('now'));

-- Ellis Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_091', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Gov. Code §§ 7060-7060.7 (Ellis Act)', 'GC §§ 7060-7060.7', 'Ellis Act — Landlord Right to Withdraw Rental Units from Market', 'Guarantees landlords the right to go out of the rental business by withdrawing all units from the rental market. Local jurisdictions may impose conditions including notice periods, relocation assistance, and right of first refusal. Widely used in San Francisco for condo conversions. Tenants receive 120-day notice (1 year for elderly/disabled).', '["Landlord has right to withdraw ALL rental units from market","Must withdraw all units — cannot selectively withdraw","120-day minimum notice to tenants","1-year notice for elderly (62+) or disabled tenants","Local relocation assistance payments required","Tenants have right of first refusal if units re-rented within 10 years","Units re-rented within 5 years must be offered at prior rent","Local jurisdictions may require additional conditions","Filed with local rent board where applicable"]', '[{"section":"7060(a)","description":"Right to go out of rental business"},{"section":"7060.2","description":"Notice requirements — 120 days"},{"section":"7060.2(b)","description":"Extended notice for elderly/disabled — 1 year"},{"section":"7060.4","description":"Right of first refusal if re-rented within 10 years"},{"section":"7060.4(b)","description":"Re-rental within 5 years at prior rent levels"},{"section":"7060.7","description":"Local authority to impose conditions"}]', '["Ellis_Act_notice","relocation_assistance","withdrawal_filing","right_of_first_refusal_notice","rent_board_filing"]', '["california-housing-tenant-audit"]', 'Local Rent Boards / California Superior Court', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- REGULIS — Habitability and Tenant Protections
-- ═══════════════════════════════════════════════════════════════════════════

-- Implied Warranty of Habitability
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_092', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1941-1942.5', 'CC §§ 1941-1942.5', 'Implied Warranty of Habitability — Landlord Duty to Maintain', 'Landlord must maintain rental property in habitable condition. Tenant remedies include repair-and-deduct (up to one month rent), rent withholding, and abandonment. Conditions rendering unit uninhabitable include lack of plumbing, heating, electricity, sanitation, weatherproofing, or presence of mold, lead paint, or pest infestation per Health & Safety Code § 17920.3.', '["Must maintain effective waterproofing and weather protection","Must maintain plumbing and gas facilities in good working order","Must maintain water supply producing hot and cold running water","Must maintain heating facilities in good working order","Must maintain electrical lighting in good working order","Must maintain grounds and building clean and sanitary","Must maintain floors, stairways, and railings in good repair","Must provide adequate trash receptacles","Tenant may repair and deduct up to one month rent (§ 1942)","Tenant may withhold rent if uninhabitable (Green v. Superior Court)","Landlord may not retaliate for habitability complaints (§ 1942.5)"]', '[{"section":"1941","description":"Landlord duty to put dwelling in habitable condition"},{"section":"1941.1","description":"Enumerated habitability standards — affirmative obligations"},{"section":"1941.2","description":"Tenant duties and limitations on repair-and-deduct"},{"section":"1941.3","description":"Dead bolt locks and window security devices required"},{"section":"1942","description":"Repair and deduct remedy — up to one month rent"},{"section":"1942.4","description":"Damages for collecting rent on uninhabitable unit"},{"section":"1942.5","description":"Anti-retaliation — cannot evict for habitability complaint"}]', '["habitability_complaint","code_enforcement_report","repair_request","rent_withholding_notice","repair_and_deduct_notice","building_inspection_report","health_department_complaint"]', '["california-housing-tenant-audit"]', 'Local Code Enforcement / California Superior Court', 1, 1, datetime('now'), datetime('now'));

-- Security Deposits
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_093', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1950.5-1950.7', 'CC §§ 1950.5-1950.7', 'Security Deposit Limits and Return Requirements', 'Limits security deposits to one month rent (unfurnished, effective 7/1/2024 under AB 12) or two months (furnished). Landlord must return deposit within 21 days of vacancy with itemized statement of deductions. Bad faith retention allows tenant to recover up to 2x deposit amount in statutory damages.', '["Deposit limit: 1 month rent unfurnished, 2 months furnished (AB 12, eff. 7/1/2024)","Must return deposit within 21 days of vacancy","Must provide itemized statement of deductions","Deductions limited to: unpaid rent, cleaning, repair of damage beyond normal wear and tear","Cannot deduct for normal wear and tear","Must provide receipts for deductions over $125","Pre-move-out inspection must be offered","Bad faith retention: tenant may recover up to 2x deposit","Landlord bears burden of proving deductions reasonable"]', '[{"section":"1950.5(a)","description":"Definition of security deposit"},{"section":"1950.5(c)","description":"Deposit limits — 1 month unfurnished, 2 months furnished"},{"section":"1950.5(e)","description":"Permissible deductions"},{"section":"1950.5(f)","description":"Itemized statement within 21 days"},{"section":"1950.5(g)","description":"21-day return requirement"},{"section":"1950.5(l)","description":"Bad faith retention — 2x penalty"},{"section":"1950.5(f)(1)","description":"Pre-move-out inspection offer required"},{"section":"1950.7","description":"Nonresidential security deposits"}]', '["security_deposit_receipt","move_out_inspection","itemized_deduction_statement","pre_move_out_inspection_notice","deposit_return_check","small_claims_complaint"]', '["california-housing-tenant-audit"]', 'California Small Claims / Superior Court', 1, 1, datetime('now'), datetime('now'));

-- Retaliatory Eviction
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_094', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1942.5', 'CC § 1942.5', 'Retaliatory Eviction and Rent Increase Protections', 'Prohibits landlord from retaliating against tenant for exercising rights including complaining to government agency about habitability, exercising repair-and-deduct rights, or organizing tenants. Creates rebuttable presumption of retaliation if adverse action occurs within 180 days of protected activity.', '["Cannot increase rent in retaliation for protected activity","Cannot decrease services in retaliation","Cannot evict in retaliation for habitability complaint","Cannot retaliate for complaint to government agency","Cannot retaliate for exercise of lawful tenant rights","Rebuttable presumption of retaliation within 180 days","Landlord defense: good faith business reason, valid cause","Tenant remedy: actual damages, punitive damages, injunctive relief","Applies to complaints to code enforcement, health department, building inspector"]', '[{"section":"1942.5(a)","description":"Protected activities — habitability complaints, tenant organizing"},{"section":"1942.5(c)","description":"Rebuttable presumption within 180 days"},{"section":"1942.5(d)","description":"Landlord defense — good faith, valid cause"},{"section":"1942.5(e)","description":"Not a defense that tenant owes rent if retaliation proven"},{"section":"1942.5(h)","description":"Remedies — actual damages, punitive damages, costs, attorney fees"}]', '["eviction_notice","rent_increase_notice","code_enforcement_complaint","habitability_complaint","tenant_organization_notice","retaliation_claim"]', '["california-housing-tenant-audit"]', 'California Superior Court', 1, 1, datetime('now'), datetime('now'));

-- Rent Stabilization — San Francisco
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_095', 'REGULIS', 'STATE_STATUTE', 'CA', 'San Francisco Administrative Code Ch. 37 (Rent Ordinance)', 'SF Admin Code Ch. 37', 'San Francisco Rent Stabilization and Arbitration Ordinance', 'Comprehensive rent control covering most rental units built before 6/13/1979. Annual allowable increase set by Rent Board (typically 60% of CPI). 16 enumerated just cause grounds for eviction. Owner move-in evictions require good faith intent and relocation payments. Buyout agreements must be filed with Rent Board.', '["Annual allowable increase set by SF Rent Board","Applies to units built before June 13, 1979","16 just cause grounds required for eviction","Owner move-in evictions: good faith intent required, relocation payment","Capital improvement passthroughs require petition to Rent Board","Buyout agreements must be filed with Rent Board","Tenant has 45 days to rescind buyout agreement","Ellis Act withdrawals subject to additional local requirements","Rent Board registration required for covered units"]', '[{"section":"37.2","description":"Definitions and covered units"},{"section":"37.3","description":"Annual allowable rent increase"},{"section":"37.9","description":"Just cause for eviction — 16 grounds"},{"section":"37.9(a)(8)","description":"Owner move-in eviction requirements"},{"section":"37.9A","description":"Relocation payments for no-fault evictions"},{"section":"37.9E","description":"Buyout agreement disclosure and filing"},{"section":"37.6","description":"Capital improvement passthroughs"}]', '["rent_increase_petition","eviction_notice","OMI_declaration","buyout_agreement","rent_board_filing","capital_improvement_petition","relocation_payment_calculation"]', '["california-housing-tenant-audit"]', 'San Francisco Rent Board', 1, 1, datetime('now'), datetime('now'));

-- Rent Stabilization — Oakland
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_096', 'REGULIS', 'STATE_STATUTE', 'CA', 'Oakland Municipal Code Ch. 8.22 (Just Cause for Eviction) & Measure EE (Rent Adjustment)', 'OMC Ch. 8.22 / Measure EE', 'Oakland Rent Adjustment and Just Cause for Eviction', 'Oakland Just Cause for Eviction Ordinance covers ALL rental units (no construction date cutoff for just cause). Rent Adjustment Program covers units built before 1/1/1983. Annual CPI-based rent increase (capped per Rent Board schedule). 12 just cause grounds. Owner move-in requires relocation payments per tenant household.', '["Just cause required for ALL rental units regardless of construction date","Rent adjustment applies to units built before January 1, 1983","Annual CPI-based rent increase set by Rent Adjustment Program","12 just cause eviction grounds","Owner move-in requires good faith intent and relocation payment","Relocation payments required for no-fault evictions","Tenant Petition available for excess rent increases","Registration required with Rent Adjustment Program","Banking of rent increases not allowed under most circumstances"]', '[{"section":"8.22.300","description":"Just cause for eviction — 12 grounds"},{"section":"8.22.360","description":"Owner move-in eviction requirements"},{"section":"8.22.450","description":"Relocation payments for no-fault evictions"},{"section":"Measure EE","description":"Rent Adjustment Program — CPI-based annual increase"},{"section":"8.22.070","description":"Registration and fee requirements"}]', '["eviction_notice","rent_increase_notice","RAP_petition","relocation_payment","owner_move_in_declaration","rent_adjustment_petition"]', '["california-housing-tenant-audit"]', 'Oakland Rent Adjustment Program', 1, 1, datetime('now'), datetime('now'));

-- FEHA Housing Discrimination
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_097', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Gov. Code §§ 12955-12956.2 (FEHA Housing)', 'GC §§ 12955-12956.2', 'Fair Employment and Housing Act — Housing Discrimination Provisions', 'California''s primary housing discrimination law, broader than federal FHA. Prohibits discrimination in sale, rental, or financing based on 18+ protected characteristics including source of income (Section 8 vouchers). Applies to all housing with limited exemptions. No minimum unit threshold unlike federal FHA (4-unit exemption). Source of income protection means landlords cannot refuse Section 8 vouchers.', '["Discrimination prohibited in sale, rental, financing of housing","Protected categories: race, color, religion, sex, gender, gender identity, gender expression, sexual orientation, marital status, national origin, ancestry, familial status, source of income, disability, genetic information, veteran/military status","Source of income includes Section 8, VASH, and other government housing subsidies","Cannot refuse to rent to Section 8 voucher holders","Reasonable accommodation required for persons with disabilities","Reasonable modification of premises allowed at tenant expense","No 4-unit owner-occupied exemption (unlike federal FHA)","Harassment in housing prohibited","Blockbusting and steering prohibited"]', '[{"section":"12955(a)","description":"Discrimination in sale or rental of housing"},{"section":"12955(d)","description":"Discrimination in terms, conditions, privileges of housing"},{"section":"12955(f)","description":"Discrimination based on familial status"},{"section":"12955(p)","description":"Source of income discrimination — Section 8"},{"section":"12955.1","description":"Reasonable accommodation for disability"},{"section":"12955.6","description":"Prohibition on harassment in housing"},{"section":"12956.1","description":"Restrictive covenant modification"},{"section":"12956.2","description":"Immunity for filing housing discrimination complaint"}]', '["housing_discrimination_complaint","Section_8_voucher_denial","reasonable_accommodation_request","CRD_complaint","lease_application","rental_advertisement","lending_discrimination_complaint"]', '["california-housing-tenant-audit"]', 'California Civil Rights Department (CRD) / HUD', 1, 1, datetime('now'), datetime('now'));

-- Federal Fair Housing Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_098', 'REGULIS', 'FEDERAL_STATUTE', 'US', '42 USC §§ 3601-3619 (Fair Housing Act)', 'FHA', 'Federal Fair Housing Act — Housing Discrimination Protections', 'Title VIII of the Civil Rights Act of 1968 prohibits discrimination in sale, rental, or financing of housing based on race, color, national origin, religion, sex, familial status, and disability. Exemptions for owner-occupied buildings with 4 or fewer units (Mrs. Murphy exemption) and religious organizations. Covers advertising, lending, insurance, and zoning.', '["Discrimination prohibited in sale or rental of dwelling","Protected classes: race, color, national origin, religion, sex, familial status, disability","Mrs. Murphy exemption: owner-occupied buildings with 4 or fewer units","Religious organization exemption for membership preference","Cannot discriminate in advertising (no preference/limitation language)","Reasonable accommodation required for disability","Reasonable modification at tenant expense for disability","Steering, blockbusting, and redlining prohibited","Discriminatory lending and insurance practices prohibited","HUD complaint within 1 year or federal court within 2 years"]', '[{"section":"3604(a)","description":"Discrimination in sale or rental"},{"section":"3604(b)","description":"Discrimination in terms and conditions"},{"section":"3604(c)","description":"Discriminatory advertising"},{"section":"3604(f)","description":"Disability discrimination — reasonable accommodation"},{"section":"3605","description":"Discrimination in residential real estate transactions"},{"section":"3606","description":"Discrimination in brokerage services"},{"section":"3607","description":"Exemptions — Mrs. Murphy, religious organizations"},{"section":"3613","description":"Private enforcement — federal court action"},{"section":"3614","description":"DOJ enforcement — pattern or practice"}]', '["HUD_complaint","fair_housing_complaint","lending_discrimination_complaint","reasonable_accommodation_request","rental_advertisement","loan_application","appraisal_report"]', '["california-housing-tenant-audit"]', 'HUD / DOJ Civil Rights Division', 1, 1, datetime('now'), datetime('now'));

-- Section 8 Housing Choice Voucher
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_099', 'REGULIS', 'FEDERAL_STATUTE', 'US', '42 USC § 1437f (Section 8 Housing Choice Voucher Program)', 'Section 8 / 42 USC § 1437f', 'Housing Choice Voucher Program (Section 8) — Tenant Protections', 'Federal rental assistance program administered by local Public Housing Authorities (PHAs). Tenant pays 30% of adjusted income; HUD subsidizes remainder up to payment standard. Landlord participation mandatory in California (FEHA source of income protection). Housing must meet HQS (Housing Quality Standards). Voucher portability allows moves between PHA jurisdictions.', '["Tenant contribution: generally 30% of adjusted monthly income","PHA sets payment standards between 90-110% of Fair Market Rent","Housing must pass HQS (Housing Quality Standards) inspection","Landlord must maintain unit to HQS throughout tenancy","HAP contract between PHA and landlord","Voucher portability — tenant may move between jurisdictions","Cannot terminate voucher holder tenancy without good cause","Annual recertification of income and family composition","In California: landlord MUST accept vouchers (FEHA source of income)"]', '[{"section":"1437f(a)","description":"Authorization of housing assistance payments"},{"section":"1437f(d)","description":"Payment standard and tenant contribution"},{"section":"1437f(o)","description":"Voucher program requirements"},{"section":"1437f(o)(7)","description":"Tenant-based portability"},{"section":"1437f(o)(10)","description":"Lease and tenancy protections"},{"section":"1437f(r)","description":"Family unification vouchers"}]', '["voucher_application","HQS_inspection","HAP_contract","lease_addendum","income_recertification","portability_request","PHA_briefing_packet"]', '["california-housing-tenant-audit"]', 'HUD / Local Public Housing Authorities', 0, 1, datetime('now'), datetime('now'));

-- Unlawful Detainer
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_100', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Code Civ. Proc. §§ 1161-1179a (Unlawful Detainer)', 'CCP §§ 1161-1179a', 'Unlawful Detainer — California Eviction Procedure', 'Summary proceeding for recovering possession of real property. Expedited timeline: 5-day answer period, priority trial setting (within 20 days of request). Strict notice requirements: 3-day notice for nonpayment/breach, 30/60-day notice for no-fault termination. Defective notice is complete defense. Tenant has right to jury trial. COVID-era protections under CCP § 1179 (SB 91/AB 832).', '["3-day notice to pay rent or quit for nonpayment","3-day notice to cure or quit for lease violation","3-day unconditional notice for nuisance, illegal activity, subletting","30-day notice for month-to-month tenancy under 1 year","60-day notice for month-to-month tenancy over 1 year","Notice must be properly served (personal, substituted, posting)","5 calendar days to file answer after service of complaint","Trial within 20 days of request for trial setting","Tenant has right to jury trial","Defective notice is complete defense to UD","Mandatory cover sheet (UD-100 series forms)","Lockout only by sheriff — no self-help eviction"]', '[{"section":"1161(2)","description":"3-day notice for nonpayment of rent"},{"section":"1161(3)","description":"3-day notice for lease violation/nuisance"},{"section":"1161(4)","description":"3-day unconditional notice for illegal activity"},{"section":"1161.1","description":"Commercial unlawful detainer"},{"section":"1167","description":"5-day answer period"},{"section":"1170.5","description":"Priority trial setting within 20 days"},{"section":"1174","description":"Judgment and writ of possession"},{"section":"1179","description":"COVID-era tenant protections (SB 91)"}]', '["3_day_notice","30_day_notice","60_day_notice","unlawful_detainer_complaint","UD_answer","writ_of_possession","sheriff_lockout_notice","trial_setting_request"]', '["california-housing-tenant-audit"]', 'California Superior Court', 1, 1, datetime('now'), datetime('now'));


