-- Tenant Right to Organize
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_101', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1942.6, 1946 (Tenant Organizing Rights)', 'CC § 1942.6', 'Tenant Right to Organize and Assemble', 'Tenants have the right to peacefully organize, assemble, canvass, and distribute literature in common areas and at their own doors. Landlord cannot prohibit tenant organizing activities, political canvassing, or peaceful assembly in common areas. Cannot be grounds for eviction.', '["Right to organize tenants and tenant associations","Right to distribute literature in common areas","Right to peacefully assemble in common areas","Right to canvass door-to-door within property","Landlord cannot prohibit or restrict organizing activities","Cannot be grounds for eviction or rent increase","Includes political speech and campaign activity"]', '[{"section":"1942.6","description":"Tenant right to organize and canvass"},{"section":"1942.5(d)","description":"Anti-retaliation for tenant organizing"}]', '["tenant_organizing_notice","association_formation","landlord_restriction_notice","retaliation_complaint"]', '["california-housing-tenant-audit"]', 'California Superior Court', 1, 1, datetime('now'), datetime('now'));

-- Rent Stabilization — Berkeley
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_102', 'REGULIS', 'STATE_STATUTE', 'CA', 'Berkeley Municipal Code Ch. 13.76 (Rent Stabilization Board)', 'BMC Ch. 13.76', 'Berkeley Rent Stabilization and Eviction for Good Cause Ordinance', 'One of California''s strongest rent control regimes. Covers units built before 6/1980. Elected 9-member Rent Stabilization Board sets annual allowable increase. Vacancy control was preempted by Costa-Hawkins but just cause protections remain comprehensive. 12 good cause grounds for eviction with mandatory registration.', '["Annual adjustment set by elected Rent Board (typically tied to CPI)","Covers units built before June 1980","Mandatory registration with Rent Stabilization Board","12 good cause grounds for eviction","Owner move-in evictions: extensive relocation requirements","Capital improvement passthroughs require Rent Board petition","Individual rent adjustment petitions available","Harassment by landlord is independently actionable"]', '[{"section":"13.76.040","description":"Rent ceiling and annual adjustment"},{"section":"13.76.130","description":"12 good cause grounds for eviction"},{"section":"13.76.110","description":"Registration requirements"},{"section":"13.76.150","description":"Owner move-in eviction requirements"},{"section":"13.76.070","description":"Individual rent adjustment petitions"}]', '["rent_board_registration","rent_increase_notice","eviction_notice","owner_move_in_petition","capital_improvement_petition","individual_adjustment_petition"]', '["california-housing-tenant-audit"]', 'Berkeley Rent Stabilization Board', 1, 1, datetime('now'), datetime('now'));

-- Mold/Lead Disclosure
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_103', 'REGULIS', 'FEDERAL_STATUTE', 'US', '42 USC § 4852d / Cal. H&S Code §§ 17920.10, 105250-105257', 'Lead/Mold Disclosure', 'Lead Paint Disclosure and Mold Remediation Requirements', 'Federal law requires lead paint disclosure for pre-1978 housing. California Health & Safety Code addresses mold remediation and landlord obligations. Lead: seller/landlord must disclose known lead-based paint hazards and provide EPA pamphlet. Mold: landlord must maintain premises free of conditions promoting mold growth; tenant must notify of visible mold.', '["Pre-1978 housing: must disclose known lead paint and hazards","Must provide EPA Protect Your Family From Lead pamphlet","10-day opportunity for buyer to conduct lead inspection","Seller/landlord must complete and sign lead disclosure form","Mold: landlord must address water intrusion and moisture conditions","Mold: tenant must notify landlord of visible mold promptly","Mold remediation must follow industry standards","Cannot retaliate against tenant for mold complaints"]', '[{"section":"42 USC 4852d","description":"Federal lead paint disclosure requirement"},{"section":"24 CFR 35","description":"HUD/EPA lead disclosure rule"},{"section":"H&S 17920.10","description":"California mold remediation standards"},{"section":"H&S 105250-105257","description":"Childhood lead poisoning prevention"}]', '["lead_paint_disclosure","EPA_lead_pamphlet","mold_remediation_report","habitability_complaint","code_enforcement_inspection","transfer_disclosure_statement"]', '["california-housing-tenant-audit"]', 'EPA / HUD / Local Code Enforcement', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- ADVOCIS — Marsy's Law (California Victims' Bill of Rights)
-- ═══════════════════════════════════════════════════════════════════════════

-- Marsy's Law — Constitutional Provision
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_051', 'ADVOCIS', 'CONSTITUTIONAL', 'CA', 'Cal. Const. Art. I, § 28(b) (Marsy''s Law — Proposition 9, 2008)', 'Art. I, § 28(b)', 'Marsy''s Law — California Crime Victims'' Bill of Rights (Constitutional)', 'Constitutional amendment (Prop 9, 2008) establishing 17 enumerated rights for crime victims. Enforceable in any court with standing to assert. Victims defined broadly to include immediate family of homicide victims. Rights cannot be waived by government without victim consent. Created one of the strongest victim rights frameworks in the United States.', '["Right to be treated with fairness and respect for privacy and dignity","Right to be reasonably protected from the defendant and persons acting on behalf of defendant","Right to have the safety of the victim and victim''s family considered in bail and release decisions","Right to prevent disclosure of confidential information to the defendant","Right to refuse interview or deposition request by defendant''s attorney","Right to confer with the prosecution and be heard at all public proceedings","Right to a speedy trial and prompt and final conclusion of the case","Right to provide information to probation department for presentence report","Right to be informed of and participate in the sentencing process","Right to receive notice of and appear at any parole hearing or proceeding","Right to restitution from the convicted wrongdoer","Right to return of property when no longer needed as evidence","Right to be informed of all rights enumerated in this section","Right to be heard at any proceeding involving post-arrest release decision","Right to be informed of the conviction, sentence, place and time of incarceration, release, escape, and scheduled parole hearing","Right to be notified of all parole procedures and to participate in the parole process","Right to safety of victim and public as primary concern in parole decisions"]', '[{"section":"28(b)(1)","description":"Right to fairness, respect, dignity, privacy"},{"section":"28(b)(2)","description":"Right to protection from defendant"},{"section":"28(b)(3)","description":"Right to safety considered in bail decisions"},{"section":"28(b)(4)","description":"Right to prevent confidential information disclosure"},{"section":"28(b)(5)","description":"Right to refuse defense interview/deposition"},{"section":"28(b)(6)","description":"Right to confer with prosecution"},{"section":"28(b)(7)","description":"Right to speedy trial"},{"section":"28(b)(8)","description":"Right to provide info for presentence report"},{"section":"28(b)(9)","description":"Right to be heard at sentencing"},{"section":"28(b)(10)","description":"Right to notice and appear at parole hearing"},{"section":"28(b)(11)","description":"Right to safety as parole primary concern"},{"section":"28(b)(12)","description":"Right to be informed of escape/release"},{"section":"28(b)(13)","description":"Right to restitution"},{"section":"28(b)(14)","description":"Right to return of property"},{"section":"28(b)(15)","description":"Right to be informed of rights"},{"section":"28(b)(16)","description":"Right to be heard at post-arrest release decision"},{"section":"28(b)(17)","description":"Right to enforcement of all rights in this section"}]', '["victim_impact_statement","restitution_order","parole_notification","bail_hearing_notice","victim_rights_card","Marsy_s_Law_notification","prosecution_conference_record"]', '["victim-rights-marsys-law-audit"]', 'California Courts / DA Victim-Witness Units', 1, 1, datetime('now'), datetime('now'));

-- Victim Rights Implementation — Penal Code
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_052', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 679-680 (Victim Rights Implementation)', 'PC §§ 679-680', 'Crime Victim Rights Implementation — Notification and Participation', 'Implementing statutes for Marsy''s Law victim rights. Requires law enforcement and courts to provide victims with notification of rights, case status updates, and information about available services. Establishes victim-witness assistance programs in each county DA office.', '["Law enforcement must provide Marsy''s Law card at first contact","Victims must be notified of right to attend court proceedings","Victims must be notified of case filing or decision not to file","DA must notify victim of all hearing dates","Court must allow victim to be heard at sentencing","Victim-witness assistance centers required in each county","CDCR must notify victim of release, escape, parole hearing","Sexual assault victims: right to free forensic exam regardless of reporting"]', '[{"section":"679","description":"Victim notification requirements — law enforcement"},{"section":"679.02","description":"Comprehensive list of victim rights to be provided"},{"section":"679.04","description":"Marsy''s Law rights card requirement"},{"section":"679.026","description":"Notification by CDCR of release and parole"},{"section":"680","description":"Sexual assault victim rights — free forensic exam, right to notification"}]', '["victim_rights_card","DA_notification_letter","court_hearing_notice","VINE_notification","victim_impact_statement","sexual_assault_exam_consent","CDCR_victim_notification"]', '["victim-rights-marsys-law-audit"]', 'Law Enforcement / DA Victim-Witness / CDCR', 0, 1, datetime('now'), datetime('now'));

-- Victim Restitution
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_053', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 1202.4-1202.46 (Victim Restitution)', 'PC §§ 1202.4-1202.46', 'Victim Restitution — Mandatory Full Restitution', 'California Constitution (Art. I, § 28(b)(13)) and Penal Code mandate full restitution to crime victims. Court must order restitution in every case where victim suffered economic loss. Restitution fine minimum $300 felony, $150 misdemeanor. Restitution order survives probation and is enforceable as civil judgment.', '["Full restitution mandatory for every crime with identifiable victim","Restitution for economic losses: medical expenses, mental health counseling, lost wages, lost/damaged property","Restitution fine: $300-$10,000 felony, $150-$1,000 misdemeanor","Court cannot consider defendant ability to pay for direct victim restitution","Restitution order enforceable as civil judgment (10-year renewable)","Victim need not be present — DA may submit claim on behalf","Interest accrues from date of loss at 10% per annum","Restitution survives completion of probation/parole"]', '[{"section":"1202.4(a)(1)","description":"Constitutional right to restitution"},{"section":"1202.4(b)","description":"Direct victim restitution — mandatory full amount"},{"section":"1202.4(b)(1)-(6)","description":"Compensable losses: medical, counseling, wages, property, relocation, funeral"},{"section":"1202.4(c)","description":"Ability to pay NOT a factor for victim restitution"},{"section":"1202.4(f)","description":"Restitution as enforceable civil judgment"},{"section":"1202.4(g)","description":"Interest on restitution from date of loss"},{"section":"1202.46","description":"Restitution hearing procedures"}]', '["restitution_order","victim_loss_statement","restitution_fine_order","abstract_of_judgment","civil_enforcement_of_restitution","proof_of_economic_loss"]', '["victim-rights-marsys-law-audit"]', 'California Superior Court / Probation Department', 1, 1, datetime('now'), datetime('now'));

-- California Victim Compensation Board
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_054', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Gov. Code §§ 13950-13966 (California Victim Compensation Board)', 'GC §§ 13950-13966', 'California Victim Compensation Board — CalVCB', 'State-funded compensation for victims of violent crime when other sources (insurance, restitution) are insufficient. Covers medical/dental, mental health counseling, income loss, funeral/burial, relocation, home security. Maximum $70,000 per claim. Application within 7 years for adults, any time for minors. No requirement that crime be reported to law enforcement (as of 2023 reforms).', '["Compensation for victims of violent crime and their derivatives","Covers: medical, dental, mental health, income loss, funeral, relocation, home security","Maximum compensation: $70,000 per claim ($35,000 for derivatives)","Application deadline: 7 years for adults, no deadline for minors","No law enforcement reporting requirement (2023 reform)","Covers domestic violence, sexual assault, child abuse, homicide survivors","Emergency awards available for immediate needs","Cannot have been involved in the crime that caused the injury","Covers undocumented immigrants without regard to immigration status"]', '[{"section":"13950","description":"CalVCB establishment and purpose"},{"section":"13951","description":"Eligible crimes and victim definitions"},{"section":"13952","description":"Application procedures and deadlines"},{"section":"13954","description":"Verification and investigation of claims"},{"section":"13955","description":"Eligibility requirements and limitations"},{"section":"13957","description":"Compensable expenses — medical, mental health, income loss"},{"section":"13957.5","description":"Funeral and burial expenses"},{"section":"13966","description":"Emergency award procedures"}]', '["CalVCB_application","victim_verification","medical_records","income_loss_documentation","funeral_expenses","relocation_request","emergency_award_request","mental_health_treatment_records"]', '["victim-rights-marsys-law-audit"]', 'California Victim Compensation Board (CalVCB)', 0, 1, datetime('now'), datetime('now'));

-- Domestic Violence Victims Rights
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_055', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 13700-13702 (Domestic Violence Response)', 'PC §§ 13700-13702', 'Domestic Violence Response — Law Enforcement Duties and Victim Rights', 'Mandates law enforcement response protocols for DV calls including written report, victim notification of rights, and information about available services. Officers must provide Marsy''s Law card, emergency protective order information, and local shelter contact. Pro-arrest policy encouraged. Dual arrest discouraged.', '["Law enforcement must make written report for every DV call","Must provide victim with Marsy''s Law rights card","Must provide information about emergency protective orders","Must provide contact for local DV shelter/services","Must note visible injuries, statements, and evidence","Pro-arrest policy: if probable cause exists, arrest is encouraged","Dual arrest discouraged — identify primary aggressor","Emergency Protective Order (EPO) available through on-call judge","Officer must assist victim in obtaining EPO if requested","Must document any prior DV incidents in household"]', '[{"section":"13700","description":"Definitions — domestic violence, abuse, cohabitant"},{"section":"13701","description":"Written policies for DV response required"},{"section":"13701(a)","description":"Pro-arrest policy when probable cause exists"},{"section":"13701(b)","description":"Primary aggressor determination — discourage dual arrest"},{"section":"13701(c)","description":"Written report and documentation requirements"},{"section":"13701(i)","description":"Victim notification of rights and services"},{"section":"13702","description":"Emergency Protective Order procedures"}]', '["DV_incident_report","EPO_application","victim_rights_notification","DV_arrest_report","primary_aggressor_determination","shelter_referral","Marsy_s_Law_card"]', '["victim-rights-marsys-law-audit","ca-post-law-enforcement-audit"]', 'California POST / Local Law Enforcement', 0, 1, datetime('now'), datetime('now'));

-- VAWA Federal
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_056', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', 'Violence Against Women Act (34 USC §§ 12291-12512)', 'VAWA', 'Violence Against Women Act — Federal DV/SA Protections', 'Federal law providing funding and framework for domestic violence, sexual assault, dating violence, and stalking response. Establishes grant programs for law enforcement training, victim services, legal assistance, and housing protections. VAWA housing provisions prohibit denial or termination of housing assistance based on DV victim status. Full Faith and Credit for protection orders across state lines.', '["Full faith and credit for protection orders across state lines","Housing protections: cannot deny/terminate housing for DV victim status","Grant programs for law enforcement DV/SA training","Legal assistance for DV/SA victims","Confidentiality protections for victim information","Immigration protections: VAWA self-petition for abused spouses of citizens/LPRs","U-visa for crime victims cooperating with law enforcement","T-visa for trafficking victims","Firearms prohibition for persons subject to protection orders (18 USC § 922(g)(8))","National DV Hotline funding"]', '[{"section":"12291","description":"Definitions — domestic violence, dating violence, stalking, sexual assault"},{"section":"12361","description":"Grant programs for law enforcement and prosecution"},{"section":"12421","description":"Legal assistance for victims"},{"section":"12472","description":"Full faith and credit for protection orders"},{"section":"12491","description":"Housing protections for DV victims"},{"section":"12512","description":"Confidentiality of victim information"},{"section":"1229(a)","description":"VAWA self-petition immigration relief"}]', '["protection_order","VAWA_self_petition","U_visa_application","housing_protection_claim","full_faith_and_credit_certification","DV_grant_application","victim_services_referral"]', '["victim-rights-marsys-law-audit"]', 'DOJ Office on Violence Against Women / HUD', 0, 1, datetime('now'), datetime('now'));
